let incode,session,container=document.getElementById("incode-container");function notifyCompletion(e){const n=new CustomEvent("incodeCompleted",{detail:e});window.dispatchEvent(n)}async function init(){session={token:document.getElementById("incode-config").value},console.log(session),incode=await window.OnBoarding.create({apiURL:"https://demo-api.incodesmile.com/0"}),await sendGeo()}async function sendGeo(){await incode.sendFingerprint({token:session.token}).catch(console.error),await incode.sendGeolocation({token:session.token}).catch(console.error),renderID()}function renderID(){incode.renderCaptureId(container,{session:session,onSuccess:renderFace,onError:console.error})}function renderFace(){incode.renderCaptureFace(container,{session:session,onSuccess:doFaceMatch,onError:console.error})}async function doFaceMatch(){await incode.processFace({token:session.token}),await incode.processId({token:session.token}),notifyCompletion({token:session.token,status:"completed"})}function waitForContainer(){document.getElementById("incode-container")?init():setTimeout(waitForContainer,100)}"loading"===document.readyState?document.addEventListener("DOMContentLoaded",waitForContainer):waitForContainer();